<template>
  <form action="" class="form">
    <h2 class="form__title">Рассчитайте стоимость автомобиля в лизинг</h2>
    <div class="form__values-wrap values">
      <div class="values__item">
        <p for="" class="values__label">Стоимость автомобиля</p>
        <div class="values__input-wrap">
          <input type="number" class="values__input" v-model="car_cost" @blur="checkCarPrice">
          <p class="values__text">₽</p>
          <input type="range" min="1000000" max="6000000" step="1" class="values__range slider-progress"
            v-model="car_cost">
        </div>
      </div>
      <div class="values__item">
        <p for="" class="values__label">Первоначальный взнос</p>
        <div class="values__input-wrap">
          <input type="number" class="values__input" v-model="initial_payment" disabled>
          <p class="values__text values__text--dec">{{initial_payment_percent}}%</p>
          <input type="range" min="10" max="60" step="1" class="values__range slider-progress"
            v-model="initial_payment_percent">
        </div>
      </div>
      <div class="values__item">
        <p for="" class="values__label">Срок лизинга</p>
        <div class="values__input-wrap">
          <input type="number" class="values__input" v-model="lease_term" @blur="checkMonths">
          <p class="values__text">мес.</p>
          <input type="range" min="1" max="60" step="1" class="values__range slider-progress" v-model="lease_term">
        </div>
      </div>
    </div>

    <div class="form__result-wrap result">
      <div class="result__item">
        <p class="result__label">Сумма договора лизинга</p>
        <p class="result__text">{{total_sum}} ₽</p>
      </div>
      <div class="result__item">
        <p class="result__label">Ежемесячный платеж от</p>
        <p class="result__text">{{mounthly_payment_from}} ₽</p>
      </div>
      <div class="result__item">
        <button class="result__btn" @click.prevent="sendData" :disabled="is_disabled">Оставить заявку</button>
      </div>

    </div>
  </form>
</template>

<script>
export default {
  data() {
    return {
      car_cost: 3300000,
      initial_payment_percent: 13,
      lease_term: 60,
      is_disabled: false,
    }
  },

  computed: {
    initial_payment: function () {
      return Math.round((this.initial_payment_percent / 100) * this.car_cost);
    },
    total_sum: function () {
      return this.initial_payment + this.lease_term * this.mounthly_payment_from;
    },
    mounthly_payment_from: function () {
      return Math.round((this.car_cost - this.initial_payment) * (((this.initial_payment_percent / 100) * Math.pow((1 + (this.initial_payment_percent / 100)), this.lease_term)) / (Math.pow((1 + (this.initial_payment_percent / 100)), this.lease_term) - 1)));
    },
    data_to_send: function () {
      return {
        car_cost: this.car_cost,
        initial_payment: this.initial_payment,
        initial_payment_percent: this.initial_payment_percent,
        lease_term: this.lease_term,
        total_sum: this.total_sum,
        mounthly_payment_from: this.mounthly_payment_from
      };
    },
  },

  methods: {
    checkCarPrice() {
      if (this.car_cost < 1000000) {
        this.car_cost = 1000000;
      } else if (this.car_cost > 6000000) {
        this.car_cost = 6000000;
      }
    },

    checkMonths() {
      if (this.lease_term < 1) {
        this.lease_term = 1;
      } else if (this.lease_term > 60) {
        this.lease_term = 60;
      }
    },

    async sendData() {
      this.is_disabled = true;
      console.log(this.is_disabled);
      let response = await fetch('https://hookb.in/eK160jgYJ6UlaRPldJ1P', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json; charset=UTF-8'
        },
        body: JSON.stringify(this.data_to_send),
      });

      let result = await response.json();
      this.is_disabled = false;
      console.log(result.success + 'работает');
      return result.success;
    },
  },
}
</script>

